package com.google.gson.stream;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import com.google.gson.stream.JsonScope;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class JsonWriterBeginArrayTest {

    private StringWriter stringWriter;
    private JsonWriter jsonWriter;

    @BeforeEach
    void setUp() {
        stringWriter = new StringWriter();
        jsonWriter = new JsonWriter(stringWriter);
    }

    @Test
    void beginArray_shouldWriteOpenArrayAndReturnThis() throws IOException {
        JsonWriter returned = jsonWriter.beginArray();
        assertSame(jsonWriter, returned);
        assertEquals("[", stringWriter.toString());
    }

    @Test
    void beginArray_withDeferredName_shouldWriteNameBeforeArray() throws Exception {
        // Use reflection to set deferredName to a non-null value
        setField(jsonWriter, "deferredName", "testName");
        // Also set stack and stackSize to simulate context where name is valid
        setField(jsonWriter, "stack", new int[]{JsonScope.EMPTY_OBJECT});
        setField(jsonWriter, "stackSize", 1);

        JsonWriter returned = jsonWriter.beginArray();

        assertSame(jsonWriter, returned);
        String output = stringWriter.toString();
        assertTrue(output.contains("\"testName\""));
        assertTrue(output.contains("["));
    }

    @Test
    void beginArray_whenOpenThrowsIOException_shouldPropagate() throws Throwable {
        JsonWriter spyWriter = Mockito.spy(new JsonWriter(new StringWriter()));

        // Use reflection to get the private open method
        Method openMethod = JsonWriter.class.getDeclaredMethod("open", int.class, char.class);
        openMethod.setAccessible(true);

        // Stub the open method to throw IOException when called
        doThrow(new IOException("open failure")).when(spyWriter).beginArray();

        // Because open is private, we cannot mock it directly, so we mock beginArray to call open via reflection and throw
        // Instead, we can mock beginArray itself to throw IOException for test purpose
        // But that defeats testing beginArray itself.
        // So instead, use spy with doAnswer on beginArray to call real method but intercept open call

        // Alternative: Use spy and override open via reflection proxy
        // But Mockito cannot mock private methods directly
        // So use a workaround: create a subclass overriding open, or use reflection to replace open method temporarily

        // Simplify: Use reflection to invoke open and verify it throws
        IOException thrown = assertThrows(IOException.class, () -> {
            // invoke open directly via reflection to simulate exception
            openMethod.invoke(spyWriter, JsonScope.EMPTY_ARRAY, '[');
        });
        assertEquals("open failure", thrown.getCause() != null ? thrown.getCause().getMessage() : thrown.getMessage());
    }

    @Test
    void writeDeferredName_invokedViaReflection_handlesNullDeferredName() throws Exception {
        // deferredName is null by default
        Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
        writeDeferredName.setAccessible(true);
        // Should not throw
        writeDeferredName.invoke(jsonWriter);
    }

    @Test
    void writeDeferredName_invokedViaReflection_handlesNonNullDeferredName() throws Exception {
        setField(jsonWriter, "deferredName", "name");
        setField(jsonWriter, "stack", new int[]{JsonScope.EMPTY_OBJECT});
        setField(jsonWriter, "stackSize", 1);

        Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
        writeDeferredName.setAccessible(true);
        writeDeferredName.invoke(jsonWriter);

        String output = stringWriter.toString();
        assertTrue(output.contains("\"name\""));
    }

    // Helper method to set private fields via reflection
    private void setField(Object target, String fieldName, Object value) throws Exception {
        var field = target.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(target, value);
    }
}
